<?php

namespace App\Http\Controllers;

use Illuminate\Contracts\View\View;

class InfoController extends Controller
{
    public function index(): View
    {
        $faqs = [
            ['q' => 'Що таке КВЕД?', 'a' => 'Коди видів економічної діяльності (КВЕД) — це статистичний інструмент для впорядкування економічної інформації. Він використовується для класифікації діяльності підприємств та ФОП в Україні. Кожен код відповідає певному виду діяльності, що дозволяє державним органам вести статистику та визначати правила оподаткування.'],
            ['q' => 'Яка різниця між КВЕД та NACE?', 'a' => 'NACE (Nomenclature des Activités Économiques dans la Communauté Européenne) — це європейська класифікація видів економічної діяльності. КВЕД — це українська національна версія, яка повністю базується на NACE, але адаптована під національні потреби.'],
            ['q' => 'Що таке NACE 2.1-UA (2027)?', 'a' => 'Це найновіша редакція класифікатора, яка відповідає оновленим європейським стандартам NACE Rev. 2.1. В Україні вона впроваджується як NACE 2.1-UA і почне повноцінно діяти у 2027 році, замінюючи поточний КВЕД-2010.'],
            ['q' => 'Чому Україна впроваджує нову класифікацію NACE 2.1?', 'a' => 'Впровадження є необхідним для гармонізації нашої статистики з європейською. Це частина угоди про асоціацію з ЄС, яка спрощує аналіз ринків, торгівлю та міжнародну звітність, забезпечуючи «єдину мову» бізнесу з Європою.'],
            ['q' => 'Коли КВЕД-2010 перестане бути актуальним?', 'a' => 'Згідно з планом переходу, КВЕД-2010 діятиме паралельно з NACE 2.1-UA протягом перехідного періоду. Очікується, що повна заміна відбудеться у 2027 році, коли всі нові реєстрації та звітність перейдуть на новий стандарт.'],
            ['q' => 'Як розшифрувати структуру коду?', 'a' => 'Структура коду зазвичай має 4 рівні: Секція (літера) — галузь; Розділ (дві цифри) — узагальнена назва; Група (три цифри) — деталізований напрямок; Клас (чотири цифри) — конкретний вид діяльності.'],
            ['q' => 'Як знайти свій КВЕД на цьому сайті?', 'a' => 'Ви можете скористатися пошуком на головній сторінці, ввівши назву вашої діяльності (наприклад, «програмування») або безпосередньо код (наприклад, «62.01»). Система покаже відповідні записи в КВЕД-2010 та їх аналоги в NACE 2.1.'],
            ['q' => 'Чи обов\'язково змінювати коди КВЕД у 2027 році?', 'a' => 'Так, для діючих підприємств та ФОП буде передбачена процедура перекодування. Наш сайт створений для того, щоб допомогти вам заздалегідь знайти свій новий код у новій класифікації на основі старого коду КВЕД-2010.'],
            ['q' => 'Як обрати основний КВЕД для бізнесу?', 'a' => 'Основним вважається той вид діяльності, який приносить найбільшу частку доходу (валової доданої вартості) вашому підприємству. Всі інші види діяльності вважаються другорядними або допоміжними.'],
            ['q' => 'Чим загрожує робота не за тими КВЕДами?', 'a' => 'Робота за незареєстрованими КВЕДами може призвести до втрати статусу платника єдиного податку, оподаткування доходів за ставкою 15% (для ФОП) та проблем із отриманням ліцензій.'],
            ['q' => 'Як додати новий КВЕД для ФОП?', 'a' => 'Зараз це можна зробити онлайн через портал або застосунок Дія, вибравши послугу «Зміна даних ФОП». Також можна звернутися до державного реєстратора особисто.'],
            ['q' => 'Що таке "Секція", "Розділ", "Група" та "Клас" у класифікаторі?', 'a' => 'Це ієрархічні рівні класифікації: від найширшого (Секція — наприклад, «Інформація та телекомунікації») до найвужчого (Клас — наприклад, «Видання комп\'ютерних ігор»).'],
            ['q' => 'Де я можу завантажити повний перелік КВЕД-2010?', 'a' => 'Офіційні переліки доступні на сайті Держстату України. Однак на нашому ресурсі ви можете зручно шукати за ключовими словами та бачити зв\'язок між редакціями.'],
            ['q' => 'Як перевірити КВЕДи контрагента?', 'a' => 'Ви можете перевірити КВЕДи будь-якої компанії або ФОП у відкритому Єдиному державному реєстрі (ЄДР) за кодом ЄДРПОУ або ІПН.'],
            ['q' => 'Чи можна мати декілька основних КВЕДів?', 'a' => 'Ні, основний КВЕД може бути лише один. Проте кількість додаткових КВЕДів законодавчо практично не обмежена.'],
            ['q' => 'Що робити, якщо мого виду діяльності немає у класифікаторі?', 'a' => 'Для нових видів діяльності часто використовуються коди з поміткою «не віднесені до інших угруповань» (н.в.і.у.) у відповідному розділі.'],
            ['q' => 'Як пов\'язані КВЕД та податки (наприклад, єдиний податок)?', 'a' => 'Для платників єдиного податку 1-ї та 2-ї груп дозволено лише певні КВЕДи. На 3-й групі обмежень менше, але вони існують для певних видів діяльності (наприклад, азартні ігри).'],
            ['q' => 'Чи відрізняються КВЕД для ФОП та ТОВ?', 'a' => 'Самі коди однакові. Однак деякі види діяльності можуть вимагати створення саме юридичної особи (ТОВ) або мати обмеження щодо ліцензування для ФОП.'],
            ['q' => 'Як відбувається перехід від КВЕД-2010 до NACE 2.1?', 'a' => 'Це процес зіставлення (маппінгу). Оскільки нова класифікація більш детальна, одному старому коду може відповідати кілька нових. На нашому сайті ви можете побачити ці таблиці відповідності.'],
            ['q' => 'Де отримати офіційне підтвердження відповідності коду?', 'a' => 'Офіційне роз\'яснення щодо належності діяльності до певного коду надає Державна служба статистики України (Держстат) за письмовим запитом.'],
            ['q' => 'КВЕД та ліцензування: який зв\'язок?', 'a' => 'Для отримання багатьох ліцензій (наприклад, торгівля алкоголем, освітня діяльність) наявність відповідного КВЕД у реєстрі є обов\'язковою передумовою.'],
            ['q' => 'Чому важливо вказувати вірний КВЕД при реєстрації?', 'a' => 'Це забезпечує правильність звітності, дозволяє користуватися пільгами та уникати штрафів через невідповідність фактичної діяльності зареєстрованим даним.'],
            ['q' => 'Чи впливає КВЕД на статистичну звітність?', 'a' => 'Так, саме за основним КВЕДом Держстат визначає перелік статистичних звітів, які ви маєте подавати.'],
            ['q' => 'Які зміни відбулися в IT-секторі з появою NACE 2.1?', 'a' => 'У новій редакції сектор цифрових послуг став більш сегментованим, що дозволяє краще виділяти розробку ПЗ, хмарні сервіси та штучний інтелект.'],
            ['q' => 'Чи можна використовувати старі коди КВЕД-2005?', 'a' => 'Ні, КВЕД-2005 повністю втратив чинність ще у 2012-2013 роках. Зараз всі діючі коди мають відповідати КВЕД-2010.'],
        ];

        return view('pages.info', compact('faqs'));
    }

    public function article(string $slug): View
    {
        return view('pages.info', [
            'slug' => $slug,
        ]);
    }
}

